I'll show you how to use the `point_in_polygon_tool` with Mastra and the Mapbox MCP server to check if the Los Angeles location falls within your service polygon.

```typescript
import { Agent } from '@mastra/core/agent';
import { createTool } from '@mastra/core/tools';
import { z } from 'zod';

class MapboxMCP {
  private url = 'https://mcp.mapbox.com/mcp';
  private headers: Record<string, string>;

  constructor(token?: string) {
    const mapboxToken = token || process.env.MAPBOX_ACCESS_TOKEN;
    this.headers = {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${mapboxToken}`
    };
  }

  async callTool(toolName: string, params: any): Promise<any> {
    const request = {
      jsonrpc: '2.0',
      id: Date.now(),
      method: 'tools/call',
      params: { name: toolName, arguments: params }
    };

    const response = await fetch(this.url, {
      method: 'POST',
      headers: this.headers,
      body: JSON.stringify(request)
    });

    const data = await response.json();

    if (data.error) {
      throw new Error(`MCP Error: ${data.error.message}`);
    }

    return data.result.content[0].text;
  }
}

const mcp = new MapboxMCP();

// Create the point-in-polygon tool for Mastra
const pointInPolygonTool = createTool({
  id: 'check-service-area',
  description: 'Check if a user location is within our service polygon area',
  inputSchema: z.object({
    userLocation: z.object({
      latitude: z.number(),
      longitude: z.number()
    }),
    servicePolygon: z.object({
      type: z.literal('Polygon'),
      coordinates: z.array(z.array(z.array(z.number())))
    })
  }),
  execute: async ({ userLocation, servicePolygon }) => {
    const result = await mcp.callTool('point_in_polygon_tool', {
      point: {
        longitude: userLocation.longitude,
        latitude: userLocation.latitude
      },
      polygon: servicePolygon
    });

    // The MCP server returns "true" or "false" as a string
    return JSON.parse(result);
  }
});

// Create agent with the tool
const serviceAgent = new Agent({
  id: 'service-area-agent',
  name: 'Service Area Checker',
  instructions: 'Check if user locations fall within our service areas using geospatial tools.',
  model: 'openai/gpt-4o',
  tools: {
    pointInPolygonTool
  }
});

// Example service polygon (Los Angeles area)
const losAngelesServiceArea = {
  type: 'Polygon' as const,
  coordinates: [[
    [-118.5, 34.2],    // Northwest corner
    [-118.1, 34.2],    // Northeast corner  
    [-118.1, 33.9],    // Southeast corner
    [-118.5, 33.9],    // Southwest corner
    [-118.5, 34.2]     // Close polygon
  ]]
};

// Check the LA location
async function checkUserInServiceArea() {
  const userLocation = {
    latitude: 34.0522,   // Los Angeles
    longitude: -118.2437
  };

  const result = await serviceAgent.generate([
    { 
      role: 'user', 
      content: `Check if this user location is within our service area. User is at ${userLocation.latitude}°N, ${userLocation.longitude}°W in Los Angeles.`
    }
  ]);

  console.log(result);

  // Or call the tool directly
  const isInServiceArea = await pointInPolygonTool.execute({
    userLocation,
    servicePolygon: losAngelesServiceArea
  });

  console.log(`User in service area: ${isInServiceArea}`);
  return isInServiceArea;
}

// Run the check
checkUserInServiceArea();
```

**Key points for the `point_in_polygon_tool`:**

1. **Point format**: Use `{longitude, latitude}` object (NOT `[lng, lat]` array)
2. **Polygon format**: Standard GeoJSON Polygon with `coordinates` array
3. **Return value**: The tool returns `"true"` or `"false"` as a string, so parse it with `JSON.parse()`

