```typescript
// Advanced service area tool with multiple zones
const advancedServiceTool = createTool({
  id: 'check-multiple-service-areas',
  description: 'Check which service zones a user location falls into',
  inputSchema: z.object({
    userLocation: z.object({
      latitude: z.number(),
      longitude: z.number()
    }),
    serviceZones: z.array(z.object({
      name: z.string(),
      polygon: z.object({
        type: z.literal('Polygon'),
        coordinates: z.array(z.array(z.array(z.number())))
      }),
      serviceType: z.string()
    }))
  }),
  execute: async ({ userLocation, serviceZones }) => {
    const results = [];

    for (const zone of serviceZones) {
