      });

      if (JSON.parse(isInZone)) {
        results.push({
          zoneName: zone.name,
          serviceType: zone.serviceType,
          inZone: true
        });
      }
    }

    return results.length > 0 ? results : [{ message: 'User not in any service area' }];
  }
});

// Define multiple service zones
