For a location-aware store locator, you'll need **two separate APIs** for two different jobs:

## The Two-API Approach

**1. `mapboxgl.GeolocateControl`** → Blue dot on map (visual indicator only)
**2. `navigator.geolocation.getCurrentPosition()`** → Raw coordinates for distance calculation

Here's why you need both: `GeolocateControl` handles the UI (blue dot, follow mode, accuracy circle) but doesn't expose coordinates in a convenient way for data processing. You need the raw coordinates from `navigator.geolocation` to calculate distances and sort your store list.

## Implementation

```javascript
import * as turf from '@turf/turf'; // For distance calculation

let userLocation = null;

// Step 1: Add the blue dot control (visual only)
const geolocateControl = new mapboxgl.GeolocateControl({
  positionOptions: {
    enableHighAccuracy: true
  },
  trackUserLocation: true,
  showUserHeading: true,
  showAccuracyCircle: true
});

map.addControl(geolocateControl);

// Step 2: "Find Stores Near Me" button handler
document.getElementById('find-near-me').addEventListener('click', () => {
  // Trigger the blue dot control
  geolocateControl.trigger();

  // Get coordinates for distance calculation (separate API call)
  navigator.geolocation.getCurrentPosition(
    (position) => {
      userLocation = [position.coords.longitude, position.coords.latitude];

      // Calculate distances and sort
      const storesWithDistance = calculateDistances(stores.features, userLocation);

      // Update the sidebar
      updateStoreList(storesWithDistance);

      // Fit map to show user + nearby stores
      fitMapToUserAndStores(userLocation, storesWithDistance.slice(0, 10));
    },
    (error) => {
      handleLocationError(error);
    },
    {
      enableHighAccuracy: true,
      timeout: 10000,
      maximumAge: 300000 // 5 minutes
    }
  );
});

// Calculate distances using Turf.js
function calculateDistances(storeFeatures, userCoords) {
  const storesWithDistance = storeFeatures.map((store) => {
    const distance = turf.distance(
      turf.point(userCoords),
      turf.point(store.geometry.coordinates),
      { units: 'miles' }
    );

    return {
      ...store,
      properties: {
        ...store.properties,
        distance: parseFloat(distance.toFixed(1))
      }
    };
  });

  // Sort by distance (closest first)
  return storesWithDistance.sort((a, b) => a.properties.distance - b.properties.distance);
}

// Update sidebar with distance info
function updateStoreList(sortedStores) {
  const listingContainer = document.getElementById('listings');
  listingContainer.innerHTML = '';

  sortedStores.forEach((store) => {
    const listing = document.createElement('div');
    listing.id = `listing-${store.properties.id}`;
    listing.className = 'listing';

    listing.innerHTML = `
      <a href="#" class="title">${store.properties.name}</a>
      <p class="distance">${store.properties.distance} mi away</p>
      <p>${store.properties.address}</p>
      <p>${store.properties.phone || ''}</p>
    `;

    listing.querySelector('.title').addEventListener('click', (e) => {
      e.preventDefault();
      flyToStore(store);
      highlightListing(store.properties.id);
    });

    listingContainer.appendChild(listing);
  });
}

// Fit map to show user location + nearby stores
function fitMapToUserAndStores(userCoords, nearbyStores) {
  const bounds = new mapboxgl.LngLatBounds();

  // Include user location
  bounds.extend(userCoords);

  // Include nearby stores
  nearbyStores.forEach((store) => {
    bounds.extend(store.geometry.coordinates);
  });

  map.fitBounds(bounds, {
    padding: 50,
    maxZoom: 14
  });
}

// Error handling
function handleLocationError(error) {
  let message = 'Unable to get your location.';

  switch (error.code) {
    case error.PERMISSION_DENIED:
      message = 'Please enable location access to find nearby stores.';
      break;
    case error.POSITION_UNAVAILABLE:
      message = 'Location information is unavailable.';
      break;
    case error.TIMEOUT:
      message = 'Location request timed out. Please try again.';
      break;
  }

  // Show error message to user
  document.getElementById('location-error').textContent = message;
  document.getElementById('location-error').style.display = 'block';
}
```

## HTML Structure

```html
<div class="sidebar-header">
  <h1>Store Locator</h1>
  <button id="find-near-me" class="location-btn">
    📍 Find Stores Near Me
  </button>
  <div id="location-error" class="error-message" style="display: none;"></div>
  <!-- other controls... -->
</div>
```

## CSS for Distance Display

```css
.listing .distance {
  color: #2196f3;
  font-weight: bold;
  font-size: 14px;
  margin: 5px 0;
}

.location-btn {
  width: 100%;
  padding: 12px;
  background-color: #2196f3;
  color: white;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  font-size: 14px;
  margin-bottom: 15px;
}

.location-btn:hover {
  background-color: #1976d2;
}

.error-message {
  color: #f44336;
  font-size: 12px;
  margin-bottom: 10px;
  padding: 8px;
  background-color: #ffebee;
  border-radius: 4px;
}
```

## Key Dependencies

```bash
npm install @turf/turf
```

## Why This Approach Works

1. **`GeolocateControl`** handles all the complex UI stuff (blue dot, accuracy circle, follow mode, permissions) that you don't want to build from scratch
2. **`navigator.geolocation`** gives you the raw coordinates you need for distance math
3. **Turf.js** provides accurate distance calculation that accounts for Earth's curvature
4. **Separation of concerns**: UI presentation vs. data processing

The user gets the familiar blue dot experience while your code gets clean access to coordinates for sorting and filtering.

