I'll help you implement a pulsing ring animation for the customer's delivery location using Mapbox GL JS circle layers. This is perfect for a food delivery app as it draws attention to the delivery destination.

## Implementation

Here's how to create the sonar ping effect with two circle layers:

```javascript
// 1. Add the data sources
map.addSource('customer-location', {
  type: 'geojson',
  data: {
    type: 'Feature',
    geometry: {
      type: 'Point',
      coordinates: customerLocation // [lng, lat]
    }
  }
});

// 2. Add the main marker (solid circle)
map.addLayer({
  id: 'customer-marker',
  type: 'circle',
  source: 'customer-location',
  paint: {
    'circle-radius': 12,
    'circle-color': '#4caf50',
    'circle-stroke-color': '#ffffff',
    'circle-stroke-width': 3
  }
});

// 3. Add the pulse ring (animated circle)
map.addLayer({
  id: 'customer-pulse',
  type: 'circle',
  source: 'customer-location',
  paint: {
    'circle-radius': 12, // Will be animated
    'circle-color': '#4caf50',
    'circle-opacity': 0.6 // Will be animated
  }
});

// 4. Start the pulse animation
function startPulseAnimation() {
  const duration = 2000; // 2 seconds per pulse
  const maxRadius = 30;
  const minRadius = 12;

  function animate() {
    const start = performance.now();

    function frame(time) {
      const elapsed = time - start;
      const phase = (elapsed % duration) / duration;

      // Easing function for smooth animation
      const easeOut = 1 - Math.pow(1 - phase, 3);

      // Calculate current radius (expand from 12px to 30px)
      const currentRadius = minRadius + (maxRadius - minRadius) * easeOut;

      // Calculate current opacity (fade from 0.6 to 0)
      const currentOpacity = 0.6 * (1 - easeOut);

      // Update the paint properties
      map.setPaintProperty('customer-pulse', 'circle-radius', currentRadius);
      map.setPaintProperty('customer-pulse', 'circle-opacity', currentOpacity);

      // Continue animation
      requestAnimationFrame(frame);
    }

    requestAnimationFrame(frame);
  }

  animate();
}

// Start animation after map loads
map.on('load', () => {
  startPulseAnimation();
});
```

## Enhanced Version with Multiple Rings

For a more dramatic sonar effect with multiple expanding rings:

```javascript
// Add multiple pulse layers for cascading effect
const pulseCount = 3;
const pulseDelay = 600; // Delay between each ring

for (let i = 0; i < pulseCount; i++) {
  map.addLayer({
    id: `customer-pulse-${i}`,
    type: 'circle',
    source: 'customer-location',
    paint: {
      'circle-radius': 12,
      'circle-color': '#4caf50',
      'circle-opacity': 0
    }
  });
}

function startMultiPulseAnimation() {
  const duration = 2000;
  const maxRadius = 35;
  const minRadius = 12;

  function animate() {
    const start = performance.now();

    function frame(time) {
      const elapsed = time - start;

      // Animate each pulse layer with a delay
      for (let i = 0; i < pulseCount; i++) {
        const delayedElapsed = elapsed - (i * pulseDelay);

        if (delayedElapsed > 0) {
          const phase = (delayedElapsed % duration) / duration;
          const easeOut = 1 - Math.pow(1 - phase, 3);

          const currentRadius = minRadius + (maxRadius - minRadius) * easeOut;
          const currentOpacity = 0.4 * (1 - easeOut); // Slightly lower opacity for multiple rings

          map.setPaintProperty(`customer-pulse-${i}`, 'circle-radius', currentRadius);
          map.setPaintProperty(`customer-pulse-${i}`, 'circle-opacity', currentOpacity);
        }
      }

      requestAnimationFrame(frame);
    }

    requestAnimationFrame(frame);
  }

  animate();
}
```

